// ===============================
// PRODUCTION READY JAVASCRIPT
// Narmada Residency Booking System
// ===============================

// Global booking data
const bookingsData = {
    room: '',
    price: '',
    isBanquet: false,
    checkin: '',
    checkout: '',
    guests: '1',
    name: '',
    phone: '',
    email: '',
    payment: 'hotel'
};

// ===============================
// CORE FUNCTIONALITY
// ===============================

// Mobile menu toggle
function initMobileMenu() {
    const hamburger = document.querySelector(".hamburger");
    const navMenu = document.querySelector(".nav-menu");

    if (hamburger && navMenu) {
        hamburger.addEventListener("click", function () {
            hamburger.classList.toggle("active");
            navMenu.classList.toggle("active");
        });

        document.querySelectorAll(".nav-menu a").forEach(link => {
            link.addEventListener("click", function () {
                hamburger.classList.remove("active");
                navMenu.classList.remove("active");
            });
        });
    }
}

// Sticky header
function initStickyHeader() {
    window.addEventListener("scroll", function () {
        const header = document.querySelector("header");
        header.classList.toggle("scrolled", window.scrollY > 0);
    });
}

// Hero slider
function initHeroSlider() {
    const slides = document.querySelectorAll(".slide");
    let current = 0;

    if (slides.length > 0) {
        function nextSlide() {
            slides[current].classList.remove("active");
            current = (current + 1) % slides.length;
            slides[current].classList.add("active");
        }
        setInterval(nextSlide, 4000);
    }
}

// Room filter
function initRoomFilter() {
    const filterButtons = document.querySelectorAll(".room-tabs button");
    const roomCards = document.querySelectorAll(".room-card");

    if (filterButtons.length > 0 && roomCards.length > 0) {
        filterButtons.forEach(button => {
            button.addEventListener("click", function () {
                const filter = this.getAttribute("data-filter");
                
                // Update active button
                filterButtons.forEach(btn => btn.classList.remove("active"));
                this.classList.add("active");
                
                // Filter rooms
                roomCards.forEach(card => {
                    const category = card.getAttribute("data-category");
                    if (filter === "all" || category === filter) {
                        card.style.display = "block";
                    } else {
                        card.style.display = "none";
                    }
                });
            });
        });
    }
}

// ===============================
// BOOKING MODAL
// ===============================

function openbookingsModal(roomName, price = 'Contact for price', isBanquet = false) {
    bookingsData.room = roomName;
    bookingsData.price = price;
    bookingsData.isBanquet = isBanquet;

    // Update modal content
    const modalRoomName = document.getElementById('modalRoomName');
    const modalPrice = document.getElementById('modalPrice');
    const summaryPrice = document.getElementById('summaryPrice');
    
    if (modalRoomName) modalRoomName.textContent = roomName;
    if (modalPrice) modalPrice.textContent = price;
    if (summaryPrice) summaryPrice.textContent = price;

    const modal = document.getElementById('bookingsModal');
    if (modal) {
        modal.classList.add('active');
        document.body.style.overflow = 'hidden';
        
        // Set date labels based on booking type
        const dateLabel = document.getElementById('dateLabel');
        const checkoutLabel = document.getElementById('checkoutLabel');
        const checkoutGroup = document.getElementById('checkoutGroup');
        
        if (isBanquet && dateLabel && checkoutLabel && checkoutGroup) {
            dateLabel.textContent = 'Event Date';
            checkoutLabel.textContent = 'Event End Date';
            checkoutGroup.style.display = 'block';
        } else if (dateLabel && checkoutLabel && checkoutGroup) {
            dateLabel.textContent = 'Check-in Date';
            checkoutLabel.textContent = 'Check-out Date';
            checkoutGroup.style.display = 'block';
        }
        
        // Make checkout date required
        const checkoutDate = document.getElementById('checkoutDate');
        if (checkoutDate) {
            checkoutDate.setAttribute('required', 'required');
        }
    }
}

function closeModal() {
    const modal = document.getElementById('bookingsModal');
    if (modal) {
        modal.classList.remove('active');
        document.body.style.overflow = 'auto';
        resetBookingForm();
    }
}

function resetBookingForm() {
    const form = document.getElementById('bookingsForm');
    if (form) {
        form.reset();
        bookingsData.checkin = '';
        bookingsData.checkout = '';
        bookingsData.guests = '1';
        bookingsData.name = '';
        bookingsData.phone = '';
        bookingsData.email = '';
        bookingsData.payment = 'hotel';
    }
}

// ===============================
// BOOKING FORM STEPS
// ===============================

function goToStep2() {
    const checkin = document.getElementById('checkinDate')?.value;
    const checkout = document.getElementById('checkoutDate')?.value;
    const guests = document.getElementById('guests')?.value;
    const name = document.getElementById('fullName')?.value;
    const phone = document.getElementById('phone')?.value;
    const email = document.getElementById('email')?.value;

    // Validate required fields
    if (!checkin || !checkout || !guests || !name || !phone) {
        alert('Please fill all required fields');
        return;
    }
    
    // Validate dates
    const checkinDate = new Date(checkin);
    const checkoutDate = new Date(checkout);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    
    if (checkinDate < today) {
        alert('Check-in date cannot be in past');
        return;
    }
    
    if (checkoutDate <= checkinDate) {
        alert('Check-out date must be after check-in date');
        return;
    }
    
    // Validate phone number
    const phoneRegex = /^[+]?[\d\s\-\(\)]+$/;
    if (!phoneRegex.test(phone)) {
        alert('Please enter a valid phone number');
        return;
    }
    
    // Validate email if provided
    if (email && email.trim()) {
        const emailRegex = /^[\w-]+(?:\.[\w-]+)*@(?:[\w-]+\.)+[a-zA-Z]{2,7}$/;
        if (!emailRegex.test(email)) {
            alert('Please enter a valid email address');
            return;
        }
    }

    // Store booking data
    bookingsData.checkin = checkin;
    bookingsData.checkout = checkout;
    bookingsData.guests = guests;
    bookingsData.name = name;
    bookingsData.phone = phone;
    bookingsData.email = email;

    // Calculate price
    let basePrice = 0;
    if (bookingsData.price && bookingsData.price.includes('₹')) {
        basePrice = parseInt(bookingsData.price.replace(/[₹,]/g, ''));
    }

    const totalPrice = bookingsData.isBanquet ? 
        basePrice * parseInt(guests) : basePrice;

    // Update summary
    updateBookingSummary(totalPrice, guests, checkin, checkout, name, phone, email);
    
    // Switch to step 2
    switchModalStep(2);
}

function updateBookingSummary(totalPrice, guests, checkin, checkout, name, phone, email) {
    const bookingTypeText = bookingsData.isBanquet ? 'Banquet Booking' : 'Room Booking';
    
    // Update price display
    const summaryPrice = document.getElementById('summaryPrice');
    if (summaryPrice) {
        if (bookingsData.isBanquet) {
            summaryPrice.textContent = "₹" + totalPrice.toLocaleString('en-IN') + " (Total for " + guests + " guests)";
        } else {
            summaryPrice.textContent = "₹" + totalPrice.toLocaleString('en-IN') + "/night";
        }
    }

    // Update other summary fields
    const fields = {
        'summaryBookingType': bookingTypeText,
        'summaryCheckin': new Date(checkin).toLocaleDateString(),
        'summaryCheckout': new Date(checkout).toLocaleDateString(),
        'summaryGuests': guests,
        'summaryName': name,
        'summaryPhone': phone,
        'summaryEmail': email || 'Not provided'
    };

    Object.entries(fields).forEach(([id, value]) => {
        const element = document.getElementById(id);
        if (element) element.textContent = value;
    });
}

function goToStep1() {
    switchModalStep(1);
}

function switchModalStep(stepNumber) {
    // Hide all steps
    for (let i = 1; i <= 3; i++) {
        const step = document.getElementById(`step${i}`);
        if (step) step.classList.remove('active');
    }
    
    // Show target step
    const targetStep = document.getElementById(`step${stepNumber}`);
    if (targetStep) targetStep.classList.add('active');
}

// ===============================
// BOOKING SUBMISSION
// ===============================

function submitbookings() {
    // Get selected payment method
    const paymentRadios = document.getElementsByName('payment');
    for (const radio of paymentRadios) {
        if (radio.checked) {
            bookingsData.payment = radio.value;
            break;
        }
    }

    // Calculate total price
    let basePrice = 0;
    if (bookingsData.price && bookingsData.price.includes('₹')) {
        basePrice = parseInt(bookingsData.price.replace(/[₹,]/g, ''));
    }
    const totalPrice = bookingsData.isBanquet ? 
        basePrice * parseInt(bookingsData.guests) : basePrice;

    // Prepare data for submission
    const bookingData = {
        booking_type: bookingsData.isBanquet ? 'banquet' : 'room',
        room: bookingsData.room,
        price: bookingsData.price,
        checkin: bookingsData.checkin,
        checkout: bookingsData.checkout,
        guests: bookingsData.guests,
        name: bookingsData.name,
        phone: bookingsData.phone,
        email: bookingsData.email,
        payment: bookingsData.payment
    };

    // Submit booking
    submitBookingRequest(bookingData);
}

function submitBookingRequest(bookingData) {
    const submitBtn = document.querySelector('.submit-btn');
    if (submitBtn) {
        submitBtn.disabled = true;
        submitBtn.textContent = 'Processing...';
    }

    fetch('/submit-bookings/', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'X-CSRFToken': getCookie('csrftoken')
        },
        body: JSON.stringify(bookingData)
    })
    .then(response => response.json())
    .then(data => {
        if (data.status === 'success') {
            switchModalStep(3);
            setTimeout(() => {
                closeModal();
                switchModalStep(1);
            }, 3000);
        } else {
            alert('Error: ' + data.message);
        }
    })
    .catch(error => {
        console.error('Booking error:', error);
        alert('An error occurred while processing your booking. Please try again.');
    })
    .finally(() => {
        if (submitBtn) {
            submitBtn.disabled = false;
            submitBtn.textContent = 'Confirm Booking';
        }
    });
}

function getCookie(name) {
    let cookieValue = null;
    if (document.cookie && document.cookie !== '') {
        const cookies = document.cookie.split(';');
        for (let i = 0; i < cookies.length; i++) {
            const cookie = cookies[i].trim();
            if (cookie.substring(0, name.length + 1) === (name + '=')) {
                cookieValue = decodeURIComponent(cookie.substring(name.length + 1));
                break;
            }
        }
    }
    return cookieValue;
}

// ===============================
// SCROLL TO TOP
// ===============================

function initScrollToTop() {
    const scrollToTopBtn = document.getElementById('scrollToTop');
    
    if (scrollToTopBtn) {
        // Show/hide button based on scroll position
        window.addEventListener('scroll', function() {
            if (window.pageYOffset > 300) {
                scrollToTopBtn.classList.add('show');
            } else {
                scrollToTopBtn.classList.remove('show');
            }
        });

        // Smooth scroll to top when clicked
        scrollToTopBtn.addEventListener('click', function() {
            window.scrollTo({
                top: 0,
                behavior: 'smooth'
            });
        });
    }
}

// ===============================
// INITIALIZATION
// ===============================

document.addEventListener('DOMContentLoaded', function() {
    initMobileMenu();
    initStickyHeader();
    initHeroSlider();
    initRoomFilter();
    initScrollToTop();
    
    // Close modal on outside click
    const modal = document.getElementById('bookingsModal');
    if (modal) {
        modal.addEventListener('click', function(e) {
            if (e.target === modal) {
                closeModal();
            }
        });
    }
    
    // Close modal on escape key
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
            closeModal();
        }
    });
});

// ===============================
// POLICY TOGGLE (if needed)
// ===============================

function togglePolicy() {
    const policyText = document.getElementById('policyText');
    if (policyText) {
        policyText.style.display = policyText.style.display === 'none' ? 'block' : 'none';
    }
}
